import type { ReactNode } from 'react';
import type { AnnotationsMarkerConfig } from './annotations-marker-props.js';
import type { BehaviorTrackingProps } from '../../../../../core/types/behavior-tracking-props.js';
import type { DataTestId } from '../../../../../core/types/data-props.js';
import type { MaskingProps } from '../../../../../core/types/masking-props.js';
import type { StylingProps } from '../../../../../core/types/styling-props.js';
import type { SeriesActionsTemplate } from '../../../types/series-actions-template.js';
import type { AnnotationsTooltipConfig } from '../components/tooltip/types/annotations-tooltip-props.js';
/**
 * Annotations actions payload data
 * @public
 */
export interface AnnotationsActionsPayload {
    /**
     * Arbitrary extra fields from the marker, forwarded from the source data or slot props
     */
    [key: string]: unknown;
    /**
     * Selected marker start
     */
    start: number | Date;
    /**
     * Selected marker end
     */
    end?: number | Date;
    /**
     * Selected marker title
     */
    title?: string;
    /**
     * Selected marker description
     */
    description?: string;
    /**
     * Selected marker symbol
     */
    symbol?: ReactNode;
}
/**
 * The annotations actions' handler, to provide a custom actions menu on the tooltip
 * @public
 */
export type AnnotationsActionsHandler = (data?: AnnotationsActionsPayload) => SeriesActionsTemplate | undefined;
/**
 * The annotations chart base prop
 * @public
 */
export interface BaseAnnotationsChartProps extends MaskingProps, StylingProps, DataTestId, BehaviorTrackingProps {
    /**
     * Specify whether track labels should show
     * @defaultValue true
     */
    showLabels?: boolean;
    /**
     * Custom annotations actions on entry selection.
     */
    annotationsActions?: AnnotationsActionsHandler;
    /**
     * Custom annotations tooltip
     */
    tooltip?: AnnotationsTooltipConfig;
}
/** @internal */
export interface AnnotationsMarkerGroup {
    /** Group priority */
    priority: number;
    /** Annotations group */
    markers: AnnotationsMarkerConfig[];
    /** Group key */
    key: string;
}
